-- ============================================================================
-- V3 Lakebase — jeu d'essai : 30 BL FICTIFS avec données factices + photos
-- À exécuter dans l'éditeur SQL du projet Lakebase V3 (après init_lakebase.sql).
-- Idempotent : ne ré-insère rien si les BL FAKE-2026-* existent déjà.
-- Répartition sur les 4 types d'opération ; réceptions ~40 % EDI NOK ;
-- 2 BL supprimés logiquement ; 1 à 3 pages JPEG "BL FICTIF" par BL.
-- ============================================================================

WITH tirage AS (
  SELECT i,
         random() AS r_statut, random() AS r_frs, random() AS r_cli,
         random() AS r_quai, random() AS r_plage, random() AS r_com
  FROM generate_series(1, 30) AS i
),
lignes AS (
  SELECT i,
    CASE WHEN i <= 2 THEN 'RECEPTION'          -- les 2 premiers : supprimés logiques
         WHEN i % 10 < 5 THEN 'RECEPTION'      -- ~50 % réceptions
         WHEN i % 10 < 8 THEN 'EXPEDITION'     -- ~30 % expéditions
         WHEN i % 10 = 8 THEN 'ARCHIVAGE_RECEPTION'
         ELSE 'ARCHIVAGE_EXPEDITION' END AS type_op,
    (ARRAY['FRN1','FRN2','TRANSPORTS DUPONT','LOGISTIQUE MARTIN'])[1 + floor(r_frs * 4)::int] AS frs,
    (ARRAY['CLIENT ALPHA','CLIENT BETA'])[1 + floor(r_cli * 2)::int] AS cli,
    (ARRAY['B15','B06EST','B06NORD','B02NORD','AUTRE'])[1 + floor(r_quai * 5)::int] AS quai,
    (ARRAY['00h-06h','06h-08h','08h-10h','10h-12h','12h-14h',
           '14h-16h','16h-18h','18h-20h','20h-00h'])[1 + floor(r_plage * 9)::int] AS plage,
    current_date - (i % 10) AS date_op,          -- étalées sur 10 jours
    r_statut, r_com
  FROM tirage
)
INSERT INTO bl_demat.suivi_bl
  (id_bl, numero_bl, date_reception, plage_horaire, nom_fournisseur, quai_reception,
   statut_bl, comment_bl, saisie_par, saisie_le, type_operation,
   est_supprime, supprime_par, supprime_le)
SELECT
  gen_random_uuid()::text,
  'FAKE-2026-' || lpad(i::text, 4, '0'),
  date_op,                                       -- V3 : la date concerne tous les types
  CASE WHEN type_op IN ('RECEPTION', 'EXPEDITION') THEN plage END,
  CASE WHEN type_op IN ('EXPEDITION', 'ARCHIVAGE_EXPEDITION') THEN cli ELSE frs END,
  CASE WHEN type_op IN ('RECEPTION', 'EXPEDITION') THEN quai END,
  CASE WHEN type_op = 'RECEPTION' AND r_statut < 0.4 THEN '0' ELSE '1' END,
  CASE WHEN type_op IN ('RECEPTION', 'EXPEDITION') AND r_com < 0.3
       THEN 'Donnée de test générée automatiquement' ELSE '' END,
  'seed-script',
  now() - make_interval(days => i % 10, hours => i % 12),
  type_op,
  i <= 2,                                        -- 2 BL supprimés logiquement
  CASE WHEN i <= 2 THEN 'seed-script' END,
  CASE WHEN i <= 2 THEN now() END
FROM lignes
WHERE NOT EXISTS (SELECT 1 FROM bl_demat.suivi_bl WHERE numero_bl LIKE 'FAKE-2026-%');

-- 1 à 3 pages JPEG par BL fictif (image "BL FICTIF" affichable dans l'app).
INSERT INTO bl_demat.pieces_jointes_bl (id_photo, id_bl, contenu, index_page)
SELECT gen_random_uuid()::text, s.id_bl, decode('', 'hex'), p.index_page
FROM bl_demat.suivi_bl AS s
CROSS JOIN LATERAL generate_series(0, abs(hashtext(s.id_bl)) % 3) AS p(index_page)
WHERE s.numero_bl LIKE 'FAKE-2026-%'
  AND NOT EXISTS (SELECT 1 FROM bl_demat.pieces_jointes_bl pj WHERE pj.id_bl = s.id_bl);

-- Contrôle : répartition des BL fictifs insérés.
SELECT type_operation, count(*) AS nb_bl,
       sum(CASE WHEN statut_bl = '0' THEN 1 ELSE 0 END) AS nb_edi_nok,
       sum(CASE WHEN est_supprime THEN 1 ELSE 0 END) AS nb_supprimes
FROM bl_demat.suivi_bl WHERE numero_bl LIKE 'FAKE-2026-%'
GROUP BY type_operation ORDER BY type_operation;

